import React, { useState } from 'react';
import { motion } from 'framer-motion';
import './QuizSetup.css';
import { FaChalkboardTeacher, FaUserGraduate, FaUserTie } from 'react-icons/fa';

const roles = [
  { label: 'Teacher', value: 'teacher' },
  { label: 'Mentor', value: 'mentor' },
  { label: 'Student', value: 'student' },
];
const difficulties = [
  { label: 'Easy', value: 'easy' },
  { label: 'Medium', value: 'medium' },
  { label: 'Hard', value: 'hard' },
];

function QuizSetup({ onGenerate }) {
  const [prompt, setPrompt] = useState('');
  const [role, setRole] = useState('teacher');
  const [difficulty, setDifficulty] = useState('easy');
  const [numQuestions, setNumQuestions] = useState(3);
  const [explanations, setExplanations] = useState(false);

  const icons = {
    teacher: <FaChalkboardTeacher color="#6366f1" size={24} />,
    mentor: <FaUserTie color="#22c55e" size={24} />,
    student: <FaUserGraduate color="#f59e42" size={24} />
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (prompt.trim()) {
      onGenerate({ prompt, role, difficulty, num_questions: numQuestions, explanations });
    }
  };

  return (
    <motion.form 
      className="quiz-setup vibrant"
      onSubmit={handleSubmit}
      initial={{ opacity: 0, y: 30 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.7 }}
    >
      <form className="quiz-setup-form" onSubmit={handleSubmit} style={{ maxWidth: 900, margin: '2rem auto', background: '#fff', borderRadius: 16, boxShadow: '0 2px 8px #eee', padding: '1.5rem 1rem' }}>
        <h2 style={{ textAlign: 'center', color: '#23254c', marginBottom: 18 }}>
          {icons[role]} Create Your AI Quiz
        </h2>
        <div style={{ display: 'flex', flexWrap: 'wrap', alignItems: 'center', gap: 18, marginBottom: 20, justifyContent: 'center' }}>
          <label style={{display:'flex',flexDirection:'column',fontWeight:500,fontSize:15,minWidth:160}}>
            Topic
            <input
              type="text"
              placeholder="e.g. Python Basics"
              value={prompt}
              onChange={e => setPrompt(e.target.value)}
              required
              style={{ padding: '0.6rem 1rem', borderRadius: 8, border: '1px solid #e5e7eb', fontSize: 15, marginTop:4 }}
            />
          </label>
          <label style={{display:'flex',flexDirection:'column',fontWeight:500,fontSize:15,minWidth:120}}>
            Role
            <select value={role} onChange={e => setRole(e.target.value)} style={{ padding: '0.6rem', borderRadius: 8, border: '1px solid #e5e7eb', fontSize: 15, marginTop:4 }}>
              {roles.map(r => (
                <option key={r.value} value={r.value}>{r.label}</option>
              ))}
            </select>
          </label>
          <label style={{display:'flex',flexDirection:'column',fontWeight:500,fontSize:15,minWidth:120}}>
            Difficulty
            <select value={difficulty} onChange={e => setDifficulty(e.target.value)} style={{ padding: '0.6rem', borderRadius: 8, border: '1px solid #e5e7eb', fontSize: 15, marginTop:4 }}>
              {difficulties.map(d => (
                <option key={d.value} value={d.value}>{d.label}</option>
              ))}
            </select>
          </label>
          <label style={{display:'flex',flexDirection:'column',fontWeight:500,fontSize:15,minWidth:120}}>
            Number
            <input
              type="number"
              min={1}
              max={10}
              value={numQuestions}
              onChange={e => setNumQuestions(Number(e.target.value))}
              style={{ width: 60, padding: '0.5rem', borderRadius: 8, border: '1px solid #e5e7eb', fontSize:15, marginTop:4 }}
            />
          </label>
          <label style={{display:'flex',alignItems:'center',fontWeight:500,fontSize:15,minWidth:120,marginTop:22}}>
            <input
              type="checkbox"
              checked={explanations}
              onChange={e => setExplanations(e.target.checked)}
              style={{ marginRight: 6 }}
            />
            Explanations
          </label>
          <button type="submit" style={{ background: '#6366f1', color: '#fff', border: 'none', borderRadius: 8, padding: '0.7rem 1.8rem', fontWeight: 600, fontSize: 17, marginTop:18 }}>Generate Quiz</button>
        </div>
      </form>
    </motion.form>
  );
}

export default QuizSetup;
